// ── Haversine ─────────────────────────────────────────────────
function haversine(lat1, lon1, lat2, lon2) {
    const R = 6371000, p = Math.PI / 180;
    const a = 0.5 - Math.cos((lat2 - lat1) * p) / 2
        + Math.cos(lat1 * p) * Math.cos(lat2 * p) * (1 - Math.cos((lon2 - lon1) * p)) / 2;
    return 2 * R * Math.asin(Math.sqrt(a));
}

// ── Nodo más cercano en el grafo ──────────────────────────────
export function nearestNode(lat, lon) {
    let bestId = null, bestDist = Infinity;
    for (const [id, [nlat, nlon]] of Object.entries(CAMPUS_NODES)) {
        const d = haversine(lat, lon, nlat, nlon);
        if (d < bestDist) { bestDist = d; bestId = id; }
    }
    return { id: bestId, dist: bestDist };
}

// ── Dijkstra ──────────────────────────────────────────────────
export function findRoute(startLat, startLon, endLat, endLon) {
    const startNode = nearestNode(startLat, startLon);
    const endNode = nearestNode(endLat, endLon);

    if (!startNode.id || !endNode.id) return straightLine(startLat, startLon, endLat, endLon);
    if (startNode.id === endNode.id) {
        return straightLine(startLat, startLon, endLat, endLon);
    }

    // Min-heap simplificado con objeto de distancias
    const dist = { [startNode.id]: 0 };
    const prev = {};
    const visited = new Set();
    const queue = [[0, startNode.id]];

    while (queue.length) {
        queue.sort((a, b) => a[0] - b[0]);
        const [d, u] = queue.shift();

        if (visited.has(u)) continue;
        visited.add(u);
        if (u === endNode.id) break;

        for (const [v, w] of (CAMPUS_GRAPH[u] || [])) {
            const nd = d + w;
            if (nd < (dist[v] ?? Infinity)) {
                dist[v] = nd;
                prev[v] = u;
                queue.push([nd, v]);
            }
        }
    }

    // Si no se encontró ruta en el grafo, fallback a línea recta
    if (!(endNode.id in dist)) return straightLine(startLat, startLon, endLat, endLon);

    // Reconstruir camino
    const path = [];
    let cur = endNode.id;
    while (cur !== startNode.id) {
        path.push(cur);
        cur = prev[cur];
        if (cur === undefined) return straightLine(startLat, startLon, endLat, endLon);
    }
    path.push(startNode.id);
    path.reverse();

    const coords = [[startLat, startLon], ...path.map(id => CAMPUS_NODES[id]), [endLat, endLon]];
    const totalDist = dist[endNode.id] + startNode.dist + endNode.dist;
    const timeMin = Math.max(1, Math.round(totalDist / 83));

    return { coords, distanceM: Math.round(totalDist), timeMin };
}

// ── Ruta en línea recta (fallback cuando el grafo no conecta) ──
function straightLine(lat1, lon1, lat2, lon2) {
    const dist = Math.round(haversine(lat1, lon1, lat2, lon2));
    const timeMin = Math.max(1, Math.round(dist / 83));
    return {
        coords: [[lat1, lon1], [lat2, lon2]],
        distanceM: dist,
        timeMin,
        esStraightLine: true,
    };
}

// ── Polylines de caminos del campus (para visualizar la red) ──
export function getCampusWays() { return CAMPUS_WAYS; }
